VALUES
  ('optometrist-moex-01024', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列何者不是低視力放大鏡的原則？', '["高正鏡片（highpluslens）眼鏡比起手持式放大鏡，可提供較長的工作距離", "手持式放大鏡比起高正鏡片眼鏡，缺點是縮小了視野", "手持式放大鏡及高正鏡片眼鏡都是讓使用者欲觀看的物體放置在鏡片的聚焦平面", "手持式放大鏡及高正鏡片眼鏡都是讓使用者欲觀看的物體在光學無限遠的位置產生影像"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01025', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '下列多種視覺電生理檢查，何者是診斷視神經至視覺皮層的視覺路徑是否異常的重要檢測法？', '["眼電圖（electrooculogram,EOG）", "視網膜電圖（electroretinogram,ERG）", "視覺誘發電位（visualevokedpotential,VEP）", "視動性試驗（optokinetictest）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01026', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '在40cm處閱讀4mm大小的字，藉由位在20cm的擴視機可放大成50mm，可更輕易看見，則其放大率 為何？', '["14.5X", "16X", "20X", "25X"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01027', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '針對低視力患者於社會心理學的變化，下列敘述何者錯誤？', '["由於視覺喪失的緣故，大多數低視力患者其他感官如味覺、嗅覺、觸覺等會補償性的增長，讓低視力患 者得到適應", "低視力患者在人際溝通方面的受限，來自於不能讀取對方的臉部表情以及嘴型，以至於容易會錯意或錯 誤理解溝通的內容", "對低視力患者來說，世界彷彿縮小了，原本能輕易到達的生活場景，都需要陪伴才能安心前往，甚至有 些患者只願意待在家中", "低視力患者恐懼疾病最後導致全盲，或是被社會及家人遺棄，有較高比率發展為憂鬱傾向"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01028', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '對低視力病患非光學輔具的敘述，下列何者正確？', '["病患通常還是靠一種感官與外界溝通", "增加對比度的輔具會增加放大鏡的使用", "以相同色系的器具盛裝食物（如白杯內裝牛奶）是一種很好的生活幫忙", "室內光源充足可以減少輔具的使用"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01029', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有雙眼視覺的低視力者，配鏡時搭配稜鏡處方會增進看近的閱讀能力，下列何種稜鏡適合如此運作？', '["基底朝上（baseup）", "基底朝下（basedown）", "基底朝內（basein）", "基底朝外（baseout）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01030', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '遠視+4.00D的低視力患者，外掛一個+10.00D的透鏡，透鏡與眼鏡相距5cm，則這種組合產生的等效屈 光度為多少？', '["+12.00D", "+14.00D", "+16.00D", "+20.00D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01031', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '關於低視力輔具中眼鏡的敘述，下列何者錯誤？', '["常見的低視力眼鏡屈光度為+4.00D至+16.00D", "屈光度越大，放大倍率越大，因此應該給予最高屈光度的眼鏡處方以便閱讀", "一低視力患者，本身具有-4.00D的近視度數，經測試其近視力放大需求，發現需要+6.00D的加入度。 因其原先有-4.00D近視，可開立+2.00D的近視用眼鏡，然而其閱讀距離為16.7cm，而非50cm", "低視力患者配戴近距離閱讀眼鏡時，若所需老花加入度較多，較不建議配戴雙焦點眼鏡（bifocals）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01032', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '低視力患者配戴近距離閱讀眼鏡時，下列敘述何者錯誤？', '["近距離閱讀眼鏡的度數高於+12.00D時，可稱為閱讀顯微鏡（readingmicroscpoes）或高正度數眼鏡（high plusspectacles）", "閱讀顯微鏡通常製作成全鏡面（full-frames）而不是半鏡面（half-eyes）", "閱讀顯微鏡在低視力患者行走時應該摘下", "閱讀顯微鏡不可配置於單眼使用，以免頭暈"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01033', 'optometrist', 'optometrist-moex-110-aa93ddf5', 'sub-optometrist-01', NULL, 'single_choice', '有關功能性視覺的評量之敘述，下列何者較不合宜？', '["主要在質化而不是量化的評量", "通常是單眼個別評量，而不是雙眼同時一起評量", "其分項比視覺功能評量來得不精確", "大都是在動態的環境中進行，而非靜態的評量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:45+00:00", "source_pdf_sha1": "8b353da32418", "answer_pdf_sha1": "3f1c93847803", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "112", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "低視力學", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
